	internal static Type? GetType (IntPtr javaClass)
	{
		ulong hash = AndroidRuntimeInternal.GetJavaClassNameHash (javaClass);
		if (hash == 0) {
			return null;
		}

		int index = MemoryExtensions.BinarySearch (s_hashes, hash);
		if (index < 0) {
			return null;
		}

		return GetTypeByIndex (index);
	}

